vector<pair<char, int>> runLength(const string& s) {
    vector<pair<char, int>> res;
    for (char ch : s) {
        if (res.empty() || res.back().first != ch) res.push_back({ch, 1});
        else res.back().second++;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s, t;
    cin >> s >> t;
    auto a = runLength(s);
    auto b = runLength(t);
    if (a.size() != b.size()) {
        cout << "No\n";
        return 0;
    }
    for (int i = 0; i < (int)a.size(); ++i) {
        if (a[i].first != b[i].first) {
            cout << "No\n";
            return 0;
        }
        if (b[i].second < a[i].second) {
            cout << "No\n";
            return 0;
        }
        if (a[i].second == 1 && b[i].second > 1) {
            cout << "No\n";
            return 0;
        }
    }
    cout << "Yes\n";
    return 0;
}

