int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    set<pair<int, int>> cells;
    for (int i = 0; i < n; ++i) {
        int x, y;
        cin >> x >> y;
        cells.insert({x, y});
    }
    set<pair<int, int>> seen;
    int dx[6] = {-1, -1, 0, 0, 1, 1};
    int dy[6] = {-1, 0, -1, 1, 0, 1};
    int ans = 0;
    for (auto start : cells) {
        if (seen.count(start)) continue;
        ++ans;
        queue<pair<int, int>> q;
        q.push(start);
        seen.insert(start);
        while (!q.empty()) {
            auto [x, y] = q.front();
            q.pop();
            for (int d = 0; d < 6; ++d) {
                pair<int, int> nxt = {x + dx[d], y + dy[d]};
                if (!cells.count(nxt) || seen.count(nxt)) continue;
                seen.insert(nxt);
                q.push(nxt);
            }
        }
    }
    cout << ans << '\n';
    return 0;
}

