int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, x, y;
    cin >> n >> x >> y;
    --x; --y;
    vector<vector<int>> graph(n);
    for (int i = 0; i < n - 1; ++i) {
        int u, v;
        cin >> u >> v;
        --u; --v;
        graph[u].push_back(v);
        graph[v].push_back(u);
    }
    vector<int> parent(n, -1);
    queue<int> q;
    parent[x] = x;
    q.push(x);
    while (!q.empty()) {
        int v = q.front();
        q.pop();
        if (v == y) break;
        for (int to : graph[v]) if (parent[to] == -1) {
            parent[to] = v;
            q.push(to);
        }
    }
    vector<int> path;
    for (int v = y; v != x; v = parent[v]) path.push_back(v);
    path.push_back(x);
    reverse(path.begin(), path.end());
    for (int i = 0; i < (int)path.size(); ++i) {
        if (i) cout << ' ';
        cout << path[i] + 1;
    }
    cout << '\n';
    return 0;
}

