map<long long, long long> memo;

long long solve(long long n) {
    if (n == 0) return 1;
    if (memo.count(n)) return memo[n];
    return memo[n] = solve(n / 2) + solve(n / 3);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;
    cout << solve(n) << '\n';
    return 0;
}

